import logging
from typing import Any

from laspy.vlrs import BaseKnownVLR
from laspy.vlrs.known import vlr_factory
from laspy.vlrs.vlrlist import VLRList

from geosat.cloud.io.las.private_known_vlrs import InnersCountVlr
from geosat.cloud.metadata.private_namespace import PrivateNamespace


def convert_to_vlr(name: str, value: Any) -> BaseKnownVLR:
    """
    Convert an item of `PrivateNamespace` to its corresponding VLR

    :param name: name of the key within `PrivateNamespace` dictionary.
    :param value: value associated to the key within `PrivateNamespace`dictionary.
    :return: Corresponding VLR.
    """
    if name == "inners":
        vlr = InnersCountVlr()
        vlr.set_data(value)
        return vlr
    raise ValueError(
        f"The private metadata key '{name}' was not recognized. Available keys are:"
        f"{list(PrivateNamespace().keys())}"
    )


def private_metadata_to_vlrs(data: PrivateNamespace) -> VLRList:
    """
    Converts all private metadata to their corresponding private known vlr.

    :param data: The private metadata we want to convert to VLRs.
    :return: The VLRs for each item of data we achieved to convert.
    """
    vlrs = []
    for name, value in data.items():
        try:
            vlr = convert_to_vlr(name, value)
        except ValueError:
            logging.warning(
                f"The item called '{name}' with a value of {value} within private "
                f"metadata was not successfully converted to VLR."
            )
        else:
            vlrs.append(vlr)
    return VLRList(vlrs)


def vlrs_to_private_metadata(vlrs: VLRList) -> PrivateNamespace:
    """
    Converts all vlrs metadata to their corresponding `PrivateNamespace` item.

    :param vlrs: The list of vlrs we want to convert.
    :return: The corresponding private metadata.
    """
    loaded_dict = PrivateNamespace()
    for vlr in vlrs:
        vlr_casted = vlr_factory(vlr)
        if isinstance(vlr_casted, InnersCountVlr):
            loaded_dict["inners"] = vlr_casted.inners_count
        else:
            logging.warning(f"A VLR was not recognized: {vlr_casted}")
    return loaded_dict
